Steps:
[AUTH role=LOYALTY_VIP_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP get_def]
  query { productConfiguration(configurableProductId: "@td(CFG_LAPTOP.id)" storeId: "{{STORE_ID}}") { configurationSections { id type options { product { id } } } } }
[GQL-EXEC get_def]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.id → SECTION_RAM_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.options.0.product.id → OPT_RAM_BASE_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.1.id → SECTION_STORAGE_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.1.options.0.product.id → OPT_STORAGE_BASE_ID]
[GQL-OP discover_pts_product]
  query { products(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "@td(LOYALTY_SETTINGS.currency_code)" first: 1 filter: "category.subtree:@td(VIRTUAL_CATALOG_B2B.id) price.@td(LOYALTY_SETTINGS.currency_code):(0 TO)") { items { id } } }
[GQL-EXEC discover_pts_product]
[GQL-CAPTURE discover_pts_product.data.products.items.0.id → PTS_PRODUCT_ID]
[GQL-OP add_item]
[GQL-VARS add_item] {"configurationSections": [{"sectionId": "{{SECTION_RAM_ID}}", "type": "Product", "option": {"productId": "{{OPT_RAM_BASE_ID}}", "quantity": 1}}, {"sectionId": "{{SECTION_STORAGE_ID}}", "type": "Product", "option": {"productId": "{{OPT_STORAGE_BASE_ID}}", "quantity": 1}}]}
  mutation AddItem($configurationSections: [ConfigurationSectionInput]) {
    addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(CFG_LAPTOP.id)" quantity: 1 configurationSections: $configurationSections }) {
      id itemsCount items { id productId productType extendedPrice { amount } }
    }
  }
[GQL-EXEC add_item]
[GQL-OP apply_coupon]
  mutation { addCoupon(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" cultureName: "en-US" couponCode: "@td(COUPONS.percentageCode)" }) { id } }
[GQL-EXEC apply_coupon]
[GQL-OP cart_usd_only]
  query { cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") { subTotal { amount } discounts { amount coupon } items { currencyCode quantity productType extendedPrice { amount } discountTotal { amount } } } }
[GQL-EXEC cart_usd_only]
[GQL-CAPTURE cart_usd_only.data.cart.discounts[?coupon=@td(COUPONS.percentageCode)].amount → COUPON_DISC_BASE]
[GQL-CAPTURE cart_usd_only.data.cart.items[?currencyCode=USD].extendedPrice.amount → USD_EXT_PRICE]
[GQL-OP add_pts_item]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "{{PTS_PRODUCT_ID}}" quantity: 1 itemCurrencyCode: "@td(LOYALTY_SETTINGS.currency_code)" }) { id } }
[GQL-EXEC add_pts_item]
[GQL-OP cart_mixed]
  query { cart(storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" currencyCode: "USD" cultureName: "en-US") { subTotal { amount } discounts { amount coupon } cartTotals { isDefaultTotalCurrency discountTotal { amount } } items { currencyCode quantity productType extendedPrice { amount } discountTotal { amount } } } }
[GQL-EXEC cart_mixed]
[GQL-CAPTURE cart_mixed.data.cart.discounts[?coupon=@td(COUPONS.percentageCode)].amount → COUPON_DISC_MIX]
[GQL-CAPTURE cart_mixed.data.cart.items[?currencyCode=@td(LOYALTY_SETTINGS.currency_code)].extendedPrice.amount → PTS_EXT_PRICE]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_post]

Assertions:
[ERRORS label=read_after_add] errors[] empty
[ERRORS label=read_q2] errors[] empty
[ERRORS label=read_q3] errors[] empty
[DATA label=read_after_add] data.cart.discounts[?coupon=@td(COUPONS.percentageCode)].amount is non-null
[VAR] {{DISC_Q2}} = {{DISC_Q1}}
[VAR] {{DISC_Q3}} = {{DISC_Q1}}

[ERRORS label=read_after_add] errors[] empty
[ERRORS label=read_u2] errors[] empty
[ERRORS label=read_u3] errors[] empty
[DATA label=read_after_add] data.cart.discounts[?coupon=@td(COUPONS.percentageCode)].amount is non-null
[VAR] {{PTS_BUCKET_SUB_2}} = {{PTS_BUCKET_SUB_1}}
[VAR] {{PTS_BUCKET_SUB_3}} = {{PTS_BUCKET_SUB_1}}
